// // This module compares two 2-bit binary inputs, A and B, and outputs whether A is less than, greater than, or equal to B.
module comparator_2bit (  
    input [1:0] A,  
    input [1:0] B,  
    output G,  
    output L,  
    output E  
);  
    assign G = (A > B);  
    assign L = (A < B);  
    assign E = (A == B);  
endmodule
